def esc(s):
 return str(s).replace('&','&amp;').replace('<','&lt;').replace('>','&gt;').replace('"','&quot;')

def header(title):
 return f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Daily Ingest Dossier — {esc(title)} — {DATE}</title><meta name="lib:group" content="report"><meta name="lib:date" content="{DATE}"><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Newsreader:opsz,wght@6..72,400;6..72,600&family=Plus+Jakarta+Sans:wght@400;500;600;700&display=swap" rel="stylesheet"><style>:root{{--brand:#01dc82;--deep:#033330;--lime:#cfe66a;--red:#b3261e;--amber:#9a6700;--ink:#0f172a;--muted:#475569;--line:#e2e8f0;--bg:#fafaf9;--card:#fff;--serif:"Newsreader",Georgia,serif;--sans:"Plus Jakarta Sans",system-ui,sans-serif}}*{{box-sizing:border-box}}body{{margin:0;background:var(--bg);color:var(--ink);font-family:var(--sans);line-height:1.55}}main{{max-width:68rem;margin:auto;padding:3rem 1.5rem 5rem}}header{{margin-bottom:2rem}}.wordmark{{display:flex;align-items:center;gap:.55rem;font-weight:700;color:var(--deep)}}h1,h2,h3{{font-family:var(--serif);color:var(--deep)}}h1{{font-size:2.35rem;line-height:1.1;margin:.8rem 0 .4rem}}h2{{font-size:1.45rem;margin:0 0 .45rem}}h3{{font-size:1.12rem;margin:.2rem 0}}p{{margin:.4rem 0 1rem}}.date,.facts{{font: .78rem ui-monospace,monospace;color:var(--muted)}}.card{{background:var(--card);border:1px solid var(--line);border-radius:.8rem;padding:1.35rem;margin:1.15rem 0}}.badges{{display:flex;gap:.45rem;flex-wrap:wrap;margin-bottom:.75rem}}.badge{{font-size:.68rem;text-transform:uppercase;letter-spacing:.07em;font-weight:700;padding:.16rem .48rem;border-radius:.35rem;background:#e2e8f0;color:#334155}}.good{{background:#dcfce7;color:#166534}}.warn{{background:#fef3c7;color:#854d0e}}.diagram{{margin:1rem 0;border:1px solid var(--line);border-radius:.55rem;padding:.8rem;background:#fff}}.diagram svg{{display:block;width:100%;height:auto}}.label{{font:600 11px var(--sans);fill:#475569;letter-spacing:.04em}}.muted{{fill:#94a3b8}}.grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:.75rem}}.fact{{background:#f8fafc;border-radius:.5rem;padding:.7rem;font-size:.88rem}}.callout{{border-left:3px solid var(--amber);background:#fffbeb;color:#713f12;padding:.65rem .85rem;border-radius:.25rem;font-size:.9rem}}a{{color:#047857;text-decoration-thickness:1px}}table{{width:100%;border-collapse:collapse;font-size:.85rem}}th,td{{border-bottom:1px solid var(--line);padding:.6rem;text-align:left;vertical-align:top}}th{{color:var(--deep)}}ol,ul{{padding-left:1.25rem}}li{{margin:.35rem 0}}.top{{border:2px solid var(--brand);background:#f0fdf4}}</style></head><body><main><header><div class="wordmark"><svg viewBox="0 0 164 195" width="21" aria-hidden="true"><path d="M117 194.5H0L12 73C17.47 66.63 21.30 65.46 28.5 64.5L34.5 0H151.5C158.44 4.4 161.28 7.18 163.5 13L153 119.5C148.8 127.15 144.97 129.55 135.5 130.5L131 184.5C127.71 190.35 125.13 192.98 117 194.5Z" fill="#01dc82"/><path d="M64 33L61 64.5H93.5L91 97H123L127.5 46.5C125.53 37.94 122.01 35.19 112.5 33H64Z" fill="#033330"/><path d="M37 147.5L41.5 98H74.5L71.5 129.5L104 130.5L100.5 162H49.5C41.82 159.35 39.68 155.53 37 147.5Z" fill="#033330"/></svg>Buildn</div><div class="date">DAILY INGEST DOSSIER · {DATE}</div><h1>{esc(title)}</h1>'''

def report(lane):
 nodes=''.join(f'<g transform="translate({20+i*250},55)"><rect width="210" height="76" rx="9" fill="#f8fafc" stroke="#cbd5e1"/><text x="105" y="29" text-anchor="middle" class="label">{esc(x[0][:26])}</text><text x="105" y="49" text-anchor="middle" class="label">{esc(x[3])}</text></g>' for i,x in enumerate(lane['items']))
 svg=f'<div class="diagram"><svg viewBox="0 0 {max(760,len(lane["items"])*250)} 180" role="img" aria-label="Signal map of selected items"><path d="M70 27 H{max(600,len(lane["items"])*210)}" stroke="#01dc82" stroke-width="3"/><text x="20" y="20" class="label">TODAY’S SIGNALS</text>{nodes}<path d="M50 145 H{max(600,len(lane["items"])*210)}" stroke="#cbd5e1" stroke-dasharray="5 5"/><text x="20" y="168" class="label">REUSABLE PATTERN → TEST WITH A BOUNDED PILOT</text></svg></div>'
 out=header(lane['title'])+f'<p>{esc(lane["readout"])}</p></header><section><article class="card"><h2>Signal map</h2><div class="badges"><span class="badge good">fresh sources</span><span class="badge">coverage gap</span></div>{svg}<div class="callout">Selection rationale: {esc(lane["rationale"])}</div></article>'
 for i,x in enumerate(lane['items'],1):
  title,url,typ,pub,what,use,caveat,action=x
  out+=f'''<article class="card"><div class="badges"><span class="badge good">{esc(typ)}</span><span class="badge">{esc(pub)}</span></div><h2>{i}. <a href="{esc(url)}">{esc(title)}</a></h2><div class="grid"><div class="fact"><strong>What changed</strong><br>{esc(what)}</div><div class="fact"><strong>Buildn / client use</strong><br>{esc(use)}</div></div><p><strong>Why useful now:</strong> {esc(lane['rationale'])}</p><div class="callout"><strong>Caveat:</strong> {esc(caveat)}</div><p><strong>Follow-up:</strong> {esc(action)}</p></article>'''
 out+='<article class="card"><h2>Use-case matrix</h2><table><thead><tr><th>Application</th><th>Buildn OS</th><th>Client work</th><th>Agent workflows</th><th>Personal leverage</th></tr></thead><tbody><tr><td>Discovery / evaluation</td><td>Review before adopting</td><td>Offer as a bounded pilot</td><td>Record acceptance tests</td><td>Save a reusable checklist</td></tr><tr><td>Production posture</td><td>Scope credentials</td><td>Keep approval ownership</td><td>Log input → action → evidence</td><td>Prefer reversible settings</td></tr></tbody></table></article><article class="card top"><h2>Top actions</h2><ol>'
 for x in lane['items'][:3]: out+=f'<li><a href="{esc(x[1])}">{esc(x[0])}</a> — {esc(x[7])}</li>'
 out+='</ol></article><article class="card"><h2>Source trail</h2><ul>' + ''.join(f'<li><a href="{esc(x[1])}">{esc(x[0])}</a> <span class="date">({esc(x[2])}, {esc(x[3])})</span></li>' for x in lane['items']) + '</ul></article></section></main></body></html>'
 return out

ledger={'date':DATE,'generated_at':datetime.now(timezone.utc).isoformat(),'editorial_thesis':'Agent capability is becoming portable and deployable, so the differentiator is the control plane: compatibility tests, scoped authority, explainable actions, and rollout evidence.','topic_groups':[]}
for lane in lanes:
 ledger['topic_groups'].append({'slug':lane['slug'],'title':lane['title'],'selection_rationale':lane['rationale'],'sources':[{'title':x[0],'url':x[1],'source_type':x[2],'published_or_updated':x[3],'why_selected':x[4],'usefulness':x[5]} for x in lane['items']]})
 (OUT/f'daily-ingest-{lane["slug"]}-{STAMP}.html').write_text(report(lane))
(OUT/f'daily-ingest-{STAMP}.json').write_text(json.dumps(ledger,indent=2))
links=''.join(f'<li><a href="{x["slug"]}.html">{x["title"]}</a> — {x["rationale"]}</li>' for x in lanes)
top=[]
for l in lanes:
 for x in l['items']:
  top.append(x)
overview=header('Daily Ingest Dossier — Overview')+f'''<p>{esc(ledger['editorial_thesis'])}</p></header><section><article class="card top"><h2>Editorial thesis</h2><p>Portable capability is arriving faster than operational discipline. Today’s three lanes favor a testable protocol seam, a reviewable delivery path, and a deliberately under-covered look at physical-world agent architecture.</p></article><article class="card"><h2>Selected lanes</h2><ul>{links}</ul></article><article class="card"><h2>All-lanes top three</h2><ol><li><a href="governed-agent-delivery.html">GitHub Issue automation controls</a> — adopt the rationale + confidence pattern, but enforce authority separately.</li><li><a href="mcp-portability.html">GitHub MCP stateless transition</a> — run a conformance check before July 28.</li><li><a href="governed-agent-delivery.html">Vercel MCP deployment + Flags evidence</a> — use disposable previews and a kill switch.</li></ol></article><article class="card"><h2>Reports</h2><div class="grid">{''.join(f'<div class="fact"><a href="{l["slug"]}.html"><strong>{l["title"]}</strong></a><br>{l["readout"]}</div>' for l in lanes)}</div></article></section></main></body></html>'''
(OUT/f'daily-ingest-overview-{STAMP}.html').write_text(overview)

# Durable coverage memory: preserve recent item detail, fold lane counts into the rolling summary.
coverage_path=Path('/root/Projects/daily-ingest-pages/topic-coverage.json')
coverage=json.loads(coverage_path.read_text()) if coverage_path.exists() else {'schema_version':1,'rolling_theme_summary':{},'item_history':[],'runs':[]}
summary=coverage.setdefault('rolling_theme_summary',{})
for lane in lanes:
    s=summary.setdefault(lane['slug'], {'title':lane['title'],'times_covered':0,'last_covered':None})
    s['title']=lane['title']; s['times_covered']=int(s.get('times_covered',0))+1; s['last_covered']=DATE
    for x in lane['items']:
        coverage.setdefault('item_history',[]).append({'date':DATE,'lane':lane['slug'],'title':x[0],'url':x[1],'source_type':x[2],'selection_rationale':x[4]})
# Keep 45 days of detailed observations (the rolling summary remains durable).
coverage['item_history']=[i for i in coverage['item_history'] if i.get('date','') >= '2026-06-09']
run={'date':DATE,'selected_lanes':[{'slug':l['slug'],'title':l['title'],'selection_rationale':l['rationale']} for l in lanes],'editorial_thesis':ledger['editorial_thesis']}
coverage['runs']=[r for r in coverage.setdefault('runs',[]) if r.get('date') != DATE]+[run]
coverage['last_run']=run; coverage['last_editorial_thesis']=ledger['editorial_thesis']; coverage['updated_at']=ledger['generated_at']
coverage_path.write_text(json.dumps(coverage,indent=2))
